import{_ as t,o as a,c as h,ai as i}from"./chunks/framework.CJDL-GS7.js";const u=JSON.parse('{"title":"Đăng ký / Đăng nhập","description":"","frontmatter":{},"headers":[],"relativePath":"register-login.md","filePath":"register-login.md","lastUpdated":null}'),o={name:"register-login.md"};function r(g,n,e,l,c,s){return a(),h("div",null,[...n[0]||(n[0]=[i('<h1 id="đang-ky-đang-nhap" tabindex="-1">Đăng ký / Đăng nhập <a class="header-anchor" href="#đang-ky-đang-nhap" aria-label="Permalink to &quot;Đăng ký / Đăng nhập&quot;">​</a></h1><h2 id="đang-ky-tai-khoan" tabindex="-1">Đăng ký tài khoản <a class="header-anchor" href="#đang-ky-tai-khoan" aria-label="Permalink to &quot;Đăng ký tài khoản&quot;">​</a></h2><h3 id="buoc-1-—-truy-cap-trang-đang-ky" tabindex="-1">Bước 1 — Truy cập trang đăng ký <a class="header-anchor" href="#buoc-1-—-truy-cap-trang-đang-ky" aria-label="Permalink to &quot;Bước 1 — Truy cập trang đăng ký&quot;">​</a></h3><p>Vào <strong>tunacademy.test</strong> → nhấn nút <strong>Đăng nhập</strong> trên thanh điều hướng.</p><h3 id="buoc-2-—-đien-thong-tin" tabindex="-1">Bước 2 — Điền thông tin <a class="header-anchor" href="#buoc-2-—-đien-thong-tin" aria-label="Permalink to &quot;Bước 2 — Điền thông tin&quot;">​</a></h3><p>Điền đầy đủ các trường bắt buộc:</p><ul><li><strong>Họ và tên</strong> — Tên hiển thị trong hệ thống</li><li><strong>Email</strong> — Dùng để đăng nhập, phải là email hợp lệ và chưa đăng ký</li><li><strong>Mật khẩu</strong> — Tối thiểu 8 ký tự</li><li><strong>Xác nhận mật khẩu</strong> — Nhập lại mật khẩu</li></ul><h3 id="buoc-3-—-hoan-tat" tabindex="-1">Bước 3 — Hoàn tất <a class="header-anchor" href="#buoc-3-—-hoan-tat" aria-label="Permalink to &quot;Bước 3 — Hoàn tất&quot;">​</a></h3><p>Sau khi đăng ký thành công, bạn sẽ được chuyển vào Dashboard. Liên hệ giáo viên hoặc admin để được thêm vào lớp học.</p><div class="warning custom-block"><p class="custom-block-title">Lưu ý</p><p>Tài khoản học sinh tự đăng ký sẽ chưa được phân vào lớp nào. Quản trị viên hoặc giáo viên sẽ thêm bạn vào lớp học tương ứng.</p></div><hr><h2 id="đang-nhap" tabindex="-1">Đăng nhập <a class="header-anchor" href="#đang-nhap" aria-label="Permalink to &quot;Đăng nhập&quot;">​</a></h2><ol><li>Vào trang chủ → nhấn <strong>Đăng nhập</strong></li><li>Nhập <strong>Email</strong> và <strong>Mật khẩu</strong></li><li>Nhấn <strong>Đăng nhập</strong></li></ol><p>Hệ thống tự động chuyển hướng đến Dashboard phù hợp với vai trò của bạn:</p><ul><li>Học sinh → <code>/student/dashboard</code></li><li>Giáo viên → <code>/teacher/dashboard</code></li><li>Quản trị viên → <code>/admin/dashboard</code></li></ul><hr><h2 id="xu-ly-loi-thuong-gap" tabindex="-1">Xử lý lỗi thường gặp <a class="header-anchor" href="#xu-ly-loi-thuong-gap" aria-label="Permalink to &quot;Xử lý lỗi thường gặp&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Lỗi</th><th>Nguyên nhân</th><th>Cách xử lý</th></tr></thead><tbody><tr><td>&quot;Email hoặc mật khẩu không đúng&quot;</td><td>Sai thông tin đăng nhập</td><td>Kiểm tra Caps Lock, thử <a href="/account-management">đặt lại mật khẩu</a></td></tr><tr><td>Trang không tải được</td><td>Lỗi kết nối</td><td>Kiểm tra internet, nhấn F5</td></tr><tr><td>Bị chuyển về trang chủ sau đăng nhập</td><td>Tài khoản chưa được phân lớp</td><td>Liên hệ giáo viên hoặc admin</td></tr></tbody></table><hr><h2 id="đang-xuat" tabindex="-1">Đăng xuất <a class="header-anchor" href="#đang-xuat" aria-label="Permalink to &quot;Đăng xuất&quot;">​</a></h2><p>Nhấn vào <strong>tên/ảnh đại diện</strong> góc trên phải → chọn <strong>Đăng xuất</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Khi dùng máy tính công cộng, hãy luôn đăng xuất sau khi sử dụng xong.</p></div>',22)])])}const p=t(o,[["render",r]]);export{u as __pageData,p as default};
